import{_ as a,o as t,c as n,ae as i}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Vivo Pre-Install","description":"","frontmatter":{"title":"Vivo Pre-Install","slug":"vivo-pre-install"},"headers":[],"relativePath":"developer-hub/vivo-pre-install.md","filePath":"developer-hub/vivo-pre-install.md"}'),o={name:"developer-hub/vivo-pre-install.md"};function r(l,e,s,p,h,d){return t(),n("div",null,[...e[0]||(e[0]=[i(`<p><em>[Image: 1280]</em></p><h3 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h3><p>Branch partners with Vivo in order to support preload/pre-install attribution of your app&#39;s campaigns. Enabling support for this attribution will allow you to properly measure the full lifecycle of your customer before they make their first few conversions in the app.</p><h3 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h3><p>In order to attribute pre-installs, you need to have completed the following:</p><ul><li>Implement the latest version of the Branch <a href="./android-basic-integration.html">Android SDK</a> into your app.</li></ul><h3 id="implementation" tabindex="-1">Implementation <a class="header-anchor" href="#implementation" aria-label="Permalink to &quot;Implementation&quot;">​</a></h3><h3 id="_1-initiate-campaign-setup" tabindex="-1">1. Initiate Campaign Setup <a class="header-anchor" href="#_1-initiate-campaign-setup" aria-label="Permalink to &quot;1. Initiate Campaign Setup&quot;">​</a></h3><p>To initialize the campaign for Vivo, you will need to gather the following:</p><table tabindex="0"><thead><tr><th>What</th><th>Obtained from</th><th>Description</th></tr></thead><tbody><tr><td><code>$3p</code> value</td><td>Branch Account Manager</td><td>Contact your Branch account manager to set up the <code>$3p</code> value: <code>a_vivo_preload</code> for the campaign</td></tr><tr><td>Campaign name</td><td>Customer</td><td>Contact the customer in order to get the name of the campaign</td></tr><tr><td>Application Id</td><td>Customer</td><td>Contact the customer to provide the application id of their project</td></tr></tbody></table><h3 id="_2-the-application-id-can-be-obtained-from-the-build-gradle-file-of-the-app-module-in-the-android-project" tabindex="-1">2. The application id can be obtained from the build.gradle file of the app module in the Android Project. <a class="header-anchor" href="#_2-the-application-id-can-be-obtained-from-the-build-gradle-file-of-the-app-module-in-the-android-project" aria-label="Permalink to &quot;2. The application id can be obtained from the build.gradle file of the app module in the Android Project.&quot;">​</a></h3><p><em>[Image: 2870]</em></p><h3 id="_3-create-the-json-file" tabindex="-1">3. Create the JSON file <a class="header-anchor" href="#_3-create-the-json-file" aria-label="Permalink to &quot;3. Create the JSON file&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>        &quot;apps&quot;: {</span></span>
<span class="line"><span>        &quot;com.maxwell.branchdemo&quot;: {</span></span>
<span class="line"><span>            &quot;preinstall_partner&quot;: &quot;a_vivo_preload&quot;,</span></span>
<span class="line"><span>            &quot;preinstall_campaign&quot;: &quot;vivopreinstall&quot;</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="_4-check-the-json-file-in-the-android-system-property" tabindex="-1">4. Check the JSON file in the Android System Property <a class="header-anchor" href="#_4-check-the-json-file-in-the-android-system-property" aria-label="Permalink to &quot;4. Check the JSON file in the Android System Property&quot;">​</a></h3><p><em>[Image: 921]</em></p><h3 id="_5-enable-vivo-in-branch" tabindex="-1">5. Enable Vivo in Branch <a class="header-anchor" href="#_5-enable-vivo-in-branch" aria-label="Permalink to &quot;5. Enable Vivo in Branch&quot;">​</a></h3><p>In the Branch Dashboard under <strong>Ads &gt; Partner Management</strong>, find/search for Vivo Preload. If you&#39;re already logged into the Branch Dashboard, you can also click <a href="https://dashboard.branch.io/ads/partner-management/a_vivo_preload?tab=settings" target="_blank" rel="noreferrer">here</a> to go there directly.</p><p><em>[Image: 1062]</em></p><h3 id="_6-view-data-in-branch" tabindex="-1">6. View Data in Branch <a class="header-anchor" href="#_6-view-data-in-branch" aria-label="Permalink to &quot;6. View Data in Branch&quot;">​</a></h3><p>As campaigns run, you will be able to measure the performance of the pre-install analytics directly on the Branch Dashboard.</p><p><em>[Image: 1052]</em></p>`,22)])])}const m=a(o,[["render",r]]);export{u as __pageData,m as default};
